const apiKey = $env.N8N_API_KEY;
let total = 0, active = 0, inactiveNames = [], liveness = '000';

try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://localhost:5678/api/v1/workflows?limit=250',
    headers: { 'X-N8N-API-KEY': apiKey },
  });
  liveness = '200';
  const workflows = resp.data || [];
  total = workflows.length;
  active = workflows.filter(w => w.active).length;
  inactiveNames = workflows.filter(w => !w.active).map(w => w.name);
} catch (e) {
  // n8n REST API unreachable or auth failed
}

return [{
  json: {
    healthy: active === total && liveness === '200',
    totalCount: total,
    activeCount: active,
    inactiveCount: total - active,
    inactiveNames,
    livenessStatus: liveness
  }
}];

const check = $input.first().json;
const state = $getWorkflowStaticData('global');

const botToken = $env.SLACK_BOT_TOKEN || '';
if (!botToken) {
  return [];
}

const currentFingerprint = `${check.healthy}|${check.activeCount}/${check.totalCount}|${check.livenessStatus}`;
const prevFingerprint = state.lastFingerprint || '';
const prevHealthy = state.lastHealthy !== false;

if (currentFingerprint === prevFingerprint) {
  return [];
}

state.lastFingerprint = currentFingerprint;
state.lastHealthy = check.healthy;
state.lastCheckedAt = new Date().toISOString();

let message = '';

if (!check.healthy) {
  const parts = [':rotating_light: *Infra Health Check — ISSUES DETECTED*\n'];
  parts.push(`*Workflows*: ${check.activeCount}/${check.totalCount} active`);
  if (check.inactiveNames && check.inactiveNames.length > 0) {
    parts.push(`  Inactive: ${check.inactiveNames.join(', ')}`);
  }
  parts.push(`*n8n liveness*: ${check.livenessStatus}`);
  message = parts.join('\n');
} else if (!prevHealthy) {
  message = `:white_check_mark: *Infra Health Check — All clear*\n${check.activeCount}/${check.totalCount} workflows active. n8n healthy.`;
} else {
  return [];
}

return [{ json: { message, channel: 'C0ALVM4PAE7' } }];
